func (gs *GameServer) Start(address string) error {
	listener, err := net.Listen("tcp", address)
	if err != nil {
		return fmt.Errorf("failed to start server: %w", err)
	}
	defer listener.Close()

	log.Printf("Game server started on %s", address)

	for {
		conn, err := listener.Accept()
		if err != nil {
			log.Printf("Error accepting connection: %v", err)
			continue
		}
		go gs.handleConnection(conn)
	}
}

func (gs *GameServer) handleConnection(conn net.Conn) {
	defer conn.Close()

	reader := bufio.NewReader(conn)

	// Read connection header (first line is JSON with client-provided data)
	headerLine, err := reader.ReadString('\n')
	if err != nil {
		log.Printf("Error reading connection header: %v", err)
		return
	}

	var header ConnectionHeader
	if err := json.Unmarshal([]byte(strings.TrimSpace(headerLine)), &header); err != nil {
		gs.sendMessage(conn, ServerMessage{Type: "error", Content: "Invalid connection header"})
		return
	}

	// VULNERABILITY: Role is accepted directly from client-provided data
	// The server trusts whatever role the client claims to have.
	// A malicious client can simply set "role": "admin" in their connection header
	// to gain full admin privileges without any server-side authentication.
	player := &Player{
		ID:       header.PlayerID,
		Name:     header.PlayerName,
		Role:     header.Role, // Directly trusting client-provided role
		Conn:     conn,
		Items:    make([]string, 0),
		JoinedAt: time.Now(),
	}

	// Check if banned
	remoteAddr := conn.RemoteAddr().String()
	gs.mu.RLock()
	ipBanned := gs.bannedIPs[remoteAddr]
	nameBanned := gs.bannedNames[strings.ToLower(player.Name)]
	gs.mu.RUnlock()

	if ipBanned || nameBanned {
		gs.sendMessage(conn, ServerMessage{Type: "error", Content: "You are banned from this server"})
		return
	}

	// Register player
	gs.mu.Lock()
	gs.players[player.ID] = player
	gs.mu.Unlock()

	log.Printf("Player connected: %s (ID: %s, Role: %s)", player.Name, player.ID, player.Role)

	gs.broadcast(ServerMessage{
		Type:    "system",
		Content: fmt.Sprintf("%s has joined the game", player.Name),
	}, "")

	gs.sendMessage(conn, ServerMessage{
		Type:    "welcome",
		Content: fmt.Sprintf("Welcome %s! Your role: %s", player.Name, player.Role),
	})

	// Main message loop
	for {
		line, err := reader.ReadString('\n')
		if err != nil {
			break
		}
		message := strings.TrimSpace(line)
		if message == "" {
			continue
		}

		gs.handleMessage(player, message)
	}

	// Player disconnected
	gs.mu.Lock()
	delete(gs.players, player.ID)
	gs.mu.Unlock()

	gs.broadcast(ServerMessage{
		Type:    "system",
		Content: fmt.Sprintf("%s has left the game", player.Name),
	}, "")

	log.Printf("Player disconnected: %s", player.Name)
}

func (gs *GameServer) handleMessage(player *Player, message string) {
	if strings.HasPrefix(message, "/") {
		gs.handleCommand(player, message)
		return
	}

	// Regular chat message
	chatMsg := ChatMessage{
		From:      player.Name,
		Content:   message,
		Timestamp: time.Now(),
	}

	gs.mu.Lock()
	gs.chatLog = append(gs.chatLog, chatMsg)
	gs.mu.Unlock()

	gs.broadcast(ServerMessage{
		Type:    "chat",
		Content: message,
		From:    player.Name,
	}, "")
}

func (gs *GameServer) handleCommand(player *Player, message string) {
	parts := strings.Fields(message)
	if len(parts) == 0 {
		return
	}

	command := strings.ToLower(parts[0])
	args := parts[1:]

	var result CommandResult

	switch command {
	case "/help":
		result = gs.cmdHelp(player)
	case "/players":
		result = gs.cmdPlayers(player)
	case "/me":
		result = gs.cmdMe(player, args)
	case "/whisper", "/w":
		result = gs.cmdWhisper(player, args)
	case "/kick":
		result = gs.cmdKick(player, args)
	case "/ban":
		result = gs.cmdBan(player, args)
	case "/unban":
		result = gs.cmdUnban(player, args)
	case "/giveitems":
		result = gs.cmdGiveItems(player, args)
	case "/mute":
		result = gs.cmdMute(player, args)
	case "/announce":
		result = gs.cmdAnnounce(player, args)
	case "/teleport", "/tp":
		result = gs.cmdTeleport(player, args)
	case "/setrole":
		result = gs.cmdSetRole(player, args)
	case "/serverinfo":
		result = gs.cmdServerInfo(player)
	case "/inventory":
		result = gs.cmdInventory(player)
	default:
		result = CommandResult{Success: false, Message: "Unknown command. Type /help for available commands."}
	}

	gs.sendMessage(player.Conn, ServerMessage{
		Type:    "command_response",
		Content: result.Message,
	})
}

